import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine(); // Read the whole line including spaces

        // Ensure that the input string does not exceed the buffer size
        int bufferSize = 10;
        char[] buffer = new char[bufferSize];

        if (name.length() > bufferSize) {
            name.getChars(0, bufferSize, buffer, 0); // Copy only up to bufferSize characters
        } else {
            name.getChars(0, name.length(), buffer, 0); // Copy entire input if it fits within buffer
        }

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
